// 1. 微调参数计算
function calculateSubtleParams(emotion) {
const baseline = { speed: 1.0, pitch: 0, volume: 1.0 };
const adjustments = {
happy: { speed: 0.08, pitch: 0.3, volume: 0.1 },
sad: { speed: -0.1, pitch: -0.4, volume: -0.1 },
angry: { speed: 0.12, pitch: 0.2, volume: 0.15 },
fearful: { speed: 0.1, pitch: 0.5, volume: 0.05 },
surprised: { speed: 0.05, pitch: 0.4, volume: 0.15 },
neutral: { speed: 0, pitch: 0, volume: 0 }
};
const adj = adjustments[emotion] || adjustments.neutral;
const strength = 0.7; // 情绪强度70%
return {
speed: baseline.speed + (adj.speed * strength),
pitch: baseline.pitch + (adj.pitch * strength),
volume: baseline.volume + (adj.volume * strength)
};
}
// 2. 添加自然停顿
function addNaturalPauses(text) {
return text
.replace(/，/g, '，<break time="100ms"/>')
.replace(/。/g, '。<break time="250ms"/>')
.replace(/？/g, '？<break time="200ms"/>')
.replace(/！/g, '！<break time="200ms"/>')
.replace(/、/g, '、<break time="80ms"/>');
}
// 3. 生成SSML
function generateSSML(text, emotion) {
const params = calculateSubtleParams(emotion);
const textWithPauses = addNaturalPauses(text);
return `
<speak>
<break time="50ms"/>
<prosody
rate="${params.speed.toFixed(2)}"
pitch="${params.pitch >= 0 ? '+' : ''}${params.pitch.toFixed(1)}st"
volume="${params.volume.toFixed(2)}">
${textWithPauses}
</prosody>
</speak>
`.trim();
}
// 4. 最终调用函数
function generateVoice(text, emotion = 'neutral') {
return {
text: text,
emotion: emotion,
params: calculateSubtleParams(emotion),
ssml: generateSSML(text, emotion),
voice_preset: "default", // 固定声线
consistency_check: "pass" // 声线一致性检查通过
};
}

