// 直接复制这个函数到你的代码中
function generateNaturalVoice(text, emotion = 'neutral') {
// 1. 微调参数映射
const baseline = { speed: 1.0, pitch: 0, volume: 1.0 };
const adjustments = {
happy: { speed: 0.08, pitch: 0.3, volume: 0.1 },
sad: { speed: -0.1, pitch: -0.4, volume: -0.1 },
angry: { speed: 0.12, pitch: 0.2, volume: 0.15 },
fearful: { speed: 0.1, pitch: 0.5, volume: 0.05 },
surprised: { speed: 0.05, pitch: 0.4, volume: 0.15 },
neutral: { speed: 0, pitch: 0, volume: 0 },
confused: { speed: -0.05, pitch: 0.2, volume: 0 }
};
// 2. 计算最终参数（70%强度）
const adj = adjustments[emotion] || adjustments.neutral;
const strength = 0.7;
const finalParams = {
speed: (baseline.speed + (adj.speed * strength)).toFixed(2),
pitch: (baseline.pitch + (adj.pitch * strength)).toFixed(1),
volume: (baseline.volume + (adj.volume * strength)).toFixed(2)
};
// 3. 添加自然停顿
const textWithPauses = text
.replace(/，/g, '，<break time="100ms"/>')
.replace(/。/g, '。<break time="250ms"/>')
.replace(/？/g, '？<break time="200ms"/>')
.replace(/！/g, '！<break time="200ms"/>')
.replace(/、/g, '、<break time="80ms"/>');
// 4. 生成SSML
const pitchStr = finalParams.pitch >= 0 ? `+${finalParams.pitch}` : finalParams.pitch;
const ssml = `
<speak>
<break time="50ms"/>
<prosody rate="${finalParams.speed}" pitch="${pitchStr}st" volume="${finalParams.volume}">
${textWithPauses}
</prosody>
</speak>
`.trim();
return {
original_text: text,
emotion: emotion,
parameters: finalParams,
ssml: ssml,
voice_preset: "default"
};
}
